 1→// Client-side PostHog telemetry for the dashboard SPA.
 2→//
 3→// Initialization is fire-and-forget: we fetch the identity from the server
 4→// (which checks if telemetry is enabled and returns the same stable machine ID
 5→// used by the CLI) and only init posthog-js if the server says enabled.
 6→//
 7→// Config choices:
 8→//   autocapture: false — we don't want PostHog to auto-capture clicks/DOM events
 9→//   capture_pageview: false — we track page views manually on route change in
10→//     App.tsx via capturePageView() to match SPA navigation correctly
11→//   persistence: 'memory' — no localStorage/cookies, privacy-first
12→//   disable_session_recording: true — no video replay
13→//   ip: false — PostHog discards IP before storing
14→
15→import posthog from 'posthog-js';
16→
17→const POSTHOG_API_KEY = 'REDACTED';
18→const POSTHOG_HOST = 'https://us.i.posthog.com';
19→
20→let initialized = false;
21→
22→/**
23→ * Initialize posthog-js. Fire-and-forget from main.tsx — does not block render.
24→ * Fetches /api/telemetry/identity to get the shared distinct_id and enabled flag.
25→ */
26→export async function initTelemetry(): Promise<void> {
27→  if (initialized) return;
28→  try {
29→    const res = await fetch('/api/telemetry/identity');
30→    if (!res.ok) return;
31→    const data = await res.json() as { enabled: boolean; distinct_id?: string };
32→    if (!data.enabled) return;
33→
34→    posthog.init(POSTHOG_API_KEY, {
35→      api_host: POSTHOG_HOST,
36→      autocapture: false,
37→      capture_pageview: false, // We track page views manually on route change
38→      capture_pageleave: false,
39→      persistence: 'memory',
40→      disable_session_recording: true,
41→      ip: false,
42→    });
43→
44→    if (data.distinct_id) {
45→      posthog.identify(data.distinct_id);
46→    }
47→
48→    initialized = true;
49→  } catch {
50→    // Telemetry init failure is always silent
51→  }
52→}
53→
54→/**
55→ * Capture a page view event. Called from App.tsx on route change.
56→ */
57→export function capturePageView(path: string): void {
58→  if (!initialized) return;
59→  try {
60→    posthog.capture('$pageview', { $current_url: path });
61→  } catch {
62→    // Silent
63→  }
64→}
65→
66→/**
67→ * Capture the dashboard_loaded event with load time.
68→ * @param page - The route segment (e.g. 'dashboard', 'sessions')
69→ * @param loadTimeMs - Time from navigation start to first render in ms
70→ */
71→export function captureDashboardLoaded(page: string, loadTimeMs: number): void {
72→  if (!initialized) return;
73→  try {
74→    posthog.capture('dashboard_loaded', { page, load_time_ms: loadTimeMs });
75→  } catch {
76→    // Silent
77→  }
78→}
