 1→import { Hono } from 'hono';
 2→import { isTelemetryEnabled, getStableMachineId } from '@code-insights/cli/utils/telemetry';
 3→
 4→const app = new Hono();
 5→
 6→// GET /api/telemetry/identity
 7→// Returns the stable distinct_id and whether telemetry is enabled.
 8→// Used by the dashboard SPA to initialize posthog-js with the same identity
 9→// as the CLI, so events from both sources are linked to the same person.
10→//
11→// Security note: this returns a deterministic hash (not PII) and is localhost-only.
12→app.get('/identity', (c) => {
13→  const enabled = isTelemetryEnabled();
14→  if (!enabled) {
15→    return c.json({ enabled: false });
16→  }
17→  return c.json({
18→    enabled: true,
19→    distinct_id: getStableMachineId(),
20→  });
21→});
22→
23→export default app;
24→

  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as os from 'os';
  4→import * as crypto from 'crypto';
  5→import { createRequire } from 'module';
  6→import { PostHog } from 'posthog-node';
  7→import { loadConfig, getConfigDir } from './config.js';
  8→
  9→// PostHog write-only API key (public — this is the standard PostHog pattern;
 10→// write-only keys can only ingest events, not read data).
 11→const POSTHOG_API_KEY = 'REDACTED';
 12→const POSTHOG_HOST = 'https://us.i.posthog.com';
 13→
 14→// Touch file path that tracks whether the disclosure has been shown.
 15→// Content is the CLI version — if version doesn't match current, notice is re-shown.
 16→const NOTICE_FILE = path.join(getConfigDir(), '.telemetry-notice-shown');
 17→
 18→// Exhaustive list of event names — string literal union for autocomplete + typo prevention.
 19→export type TelemetryEventName =
 20→  | 'cli_sync'
 21→  | 'cli_stats'
 22→  | 'cli_dashboard'
 23→  | 'cli_init'
 24→  | 'cli_config'
 25→  | 'cli_reset'
 26→  | 'cli_install_hook'
 27→  | 'cli_status'
 28→  | 'cli_open'
 29→  | 'analysis_run'
 30→  | 'insight_generated'
 31→  | 'export_run'
 32→  | 'dashboard_loaded';
 33→
 34→// PostHog client — lazily initialized on first trackEvent call.
 35→// null when telemetry is disabled or init hasn't happened yet.
 36→let client: PostHog | null = null;
 37→
 38→/**
 39→ * Check if telemetry is enabled.
 40→ *
 41→ * Check order (first match wins):
 42→ * 1. CODE_INSIGHTS_TELEMETRY_DISABLED=1 env var — respects CI/automation opt-out
 43→ * 2. DO_NOT_TRACK=1 env var — respects the community standard
 44→ * 3. config.telemetry field — user's explicit preference
 45→ * 4. Default: true (opt-out model)
 46→ */
 47→export function isTelemetryEnabled(): boolean {
 48→  if (process.env.CODE_INSIGHTS_TELEMETRY_DISABLED === '1') return false;
 49→  if (process.env.DO_NOT_TRACK === '1') return false;
 50→
 51→  const config = loadConfig();
 52→  if (config !== null && typeof config.telemetry === 'boolean') {
 53→    return config.telemetry;
 54→  }
 55→
 56→  return true;
 57→}
 58→
 59→/**
 60→ * Get (or lazily create) the PostHog client.
 61→ * Returns null when telemetry is disabled.
 62→ *
 63→ * flushAt: 1 — flush immediately after each capture(); CLI is short-lived
 64→ * flushInterval: 0 — no background timer; avoids keeping process alive
 65→ */
 66→function getPostHogClient(): PostHog | null {
 67→  if (!isTelemetryEnabled()) return null;
 68→  if (!client) {
 69→    client = new PostHog(POSTHOG_API_KEY, {
 70→      host: POSTHOG_HOST,
 71→      flushAt: 1,
 72→      flushInterval: 0,
 73→    });
 74→  }
 75→  return client;
 76→}
 77→
 78→/**
 79→ * Flush and shut down the PostHog client.
 80→ * Call this in server SIGINT/SIGTERM handlers before process.exit().
 81→ * No-op if telemetry is disabled or client was never initialized.
 82→ */
 83→export async function shutdownTelemetry(): Promise<void> {
 84→  if (client) {
 85→    await client.shutdown();
 86→    client = null;
 87→  }
 88→}
 89→
 90→/**
 91→ * Show the telemetry disclosure notice if it hasn't been shown for this CLI version.
 92→ *
 93→ * Uses a version-stamped touch file at ~/.code-insights/.telemetry-notice-shown.
 94→ * Re-shown when the CLI version changes (catches existing users on upgrades).
 95→ * Only displays if telemetry is enabled.
 96→ *
 97→ * Returns true if the notice was shown.
 98→ */
 99→export function showTelemetryNoticeIfNeeded(): boolean {
100→  if (!isTelemetryEnabled()) return false;
101→
102→  const currentVersion = getCliVersion();
103→  let shownVersion: string | null = null;
104→
105→  if (fs.existsSync(NOTICE_FILE)) {
106→    try {
107→      shownVersion = fs.readFileSync(NOTICE_FILE, 'utf-8').trim();
108→    } catch {
109→      // Can't read — treat as not shown
110→    }
111→  }
112→
113→  if (shownVersion === currentVersion) return false;
114→
115→  // Show the updated disclosure banner
116→  console.log('');
117→  console.log('  Code Insights collects anonymous usage data to improve the CLI and dashboard.');
118→  console.log('  Includes: commands, page views, OS, CLI version, AI tool types, session counts,');
119→  console.log('  LLM provider, performance timing.');
120→  console.log('  Never includes: file paths, project names, session content, API keys, or personal data.');
121→  console.log('');
122→  console.log('  Disable: code-insights telemetry disable');
123→  console.log('  Details: code-insights telemetry status');
124→  console.log('');
125→
126→  // Write the current version as content — best-effort, non-fatal
127→  try {
128→    const configDir = getConfigDir();
129→    if (!fs.existsSync(configDir)) {
130→      fs.mkdirSync(configDir, { recursive: true, mode: 0o700 });
131→    }
132→    fs.writeFileSync(NOTICE_FILE, currentVersion, { encoding: 'utf-8', mode: 0o600 });
133→  } catch {
134→    // Non-fatal — if we can't write, we'll show the notice again next time
135→  }
136→
137→  return true;
138→}
139→
140→/**
141→ * Classify an error into a structured error_type + error_message pair.
142→ * Used to enrich trackEvent calls and captureError calls with consistent error metadata.
143→ */
144→export function classifyError(error: unknown): { error_type: string; error_message: string } {
145→  if (error instanceof Error) {
146→    if (error.name === 'AbortError') {
147→      return { error_type: 'abort', error_message: error.message };
148→    }
149→    // SyntaxError from JSON.parse
150→    if (error instanceof SyntaxError) {
151→      return { error_type: 'json_parse_error', error_message: error.message };
152→    }
153→    return { error_type: 'api_error', error_message: error.message };
154→  }
155→  return { error_type: 'unknown', error_message: String(error) };
156→}
157→
158→/**
159→ * Capture an exception in PostHog. Never throws — telemetry must never break the CLI.
160→ * Respects the same opt-out as trackEvent.
161→ *
162→ * @param error - The caught error (or unknown value)
163→ * @param properties - Additional context properties (provider, model, etc.)
164→ */
165→export function captureError(error: unknown, properties?: Record<string, unknown>): void {
166→  const ph = getPostHogClient();
167→  if (!ph) return;
168→
169→  try {
170→    const { error_type, error_message } = classifyError(error);
171→    ph.capture({
172→      distinctId: getStableMachineId(),
173→      event: '$exception',
174→      properties: {
175→        $exception_message: error_message,
176→        $exception_type: error_type,
177→        ...(properties ?? {}),
178→      },
179→    });
180→  } catch {
181→    // Swallow all errors — telemetry failures are silent
182→  }
183→}
184→
185→/**
186→ * Send a telemetry event. Never throws — telemetry must never break the CLI.
187→ *
188→ * @param event - Event name from TelemetryEventName union
189→ * @param properties - Arbitrary event properties (success, duration_ms, etc.)
190→ */
191→export function trackEvent(event: TelemetryEventName, properties?: Record<string, unknown>): void {
192→  const ph = getPostHogClient();
193→  if (!ph) return;
194→
195→  try {
196→    ph.capture({
197→      distinctId: getStableMachineId(),
198→      event,
199→      properties: properties ?? {},
200→    });
201→  } catch {
202→    // Swallow all errors — telemetry failures are silent
203→  }
204→}
205→
206→/**
207→ * Set person-level properties via PostHog identify().
208→ * Call once after the DB is open (so total_sessions can be queried).
209→ *
210→ * Commands that never open the DB (init, config, telemetry) can skip this —
211→ * PostHog retains person properties from previous calls.
212→ */
213→export async function identifyUser(): Promise<void> {
214→  const ph = getPostHogClient();
215→  if (!ph) return;
216→
217→  try {
218→    const { getDb } = await import('../db/client.js');
219→    const db = getDb();
220→    const row = db.prepare('SELECT COUNT(*) as count FROM sessions').get() as { count: number };
221→
222→    ph.identify({
223→      distinctId: getStableMachineId(),
224→      properties: {
225→        cli_version: getCliVersion(),
226→        node_version: process.version.replace('v', ''),
227→        os: process.platform,
228→        arch: process.arch,
229→        installed_providers: detectProviders(),
230→        has_hook: detectHook(),
231→        total_sessions: row.count,
232→      },
233→    });
234→  } catch {
235→    // Non-fatal — identify failure doesn't affect event tracking
236→  }
237→}
238→
239→/**
240→ * Build a preview of what would be collected and sent.
241→ * Used by `code-insights telemetry status` to show users what is collected.
242→ */
243→export function buildEventPreview(): Record<string, unknown> {
244→  return {
245→    distinct_id: getStableMachineId(),
246→    cli_version: getCliVersion(),
247→    node_version: process.version.replace('v', ''),
248→    os: process.platform,
249→    arch: process.arch,
250→    installed_providers: detectProviders(),
251→    has_hook: detectHook(),
252→    total_sessions: '(queried from SQLite when DB is open)',
253→    sample_event: {
254→      event: 'cli_sync',
255→      properties: {
256→        duration_ms: 1234,
257→        sessions_synced: 5,
258→        sessions_by_provider: { 'claude-code': 4, cursor: 1 },
259→        errors: 0,
260→        source_filter: null,
261→        success: true,
262→      },
263→    },
264→  };
265→}
266→
267→// ---------------------------------------------------------------------------
268→// Internal helpers
269→// ---------------------------------------------------------------------------
270→
271→/**
272→ * Stable machine ID — does NOT rotate monthly.
273→ *
274→ * Format: SHA-256(hostname:username:code-insights).slice(0, 16)
275→ *
276→ * No PII: hostname and username are never transmitted, only their hash.
277→ * Deterministic: same machine always produces the same ID (survives reinstalls).
278→ */
279→export function getStableMachineId(): string {
280→  let username: string;
281→  try {
282→    username = os.userInfo().username;
283→  } catch {
284→    // os.userInfo() throws in Docker/CI when UID has no /etc/passwd entry
285→    username = `uid-${process.getuid?.() ?? 'unknown'}`;
286→  }
287→
288→  const input = [os.hostname(), username, 'code-insights'].join(':');
289→  return crypto.createHash('sha256').update(input).digest('hex').slice(0, 16);
290→}
291→
292→/**
293→ * Read CLI version from package.json.
294→ */
295→function getCliVersion(): string {
296→  try {
297→    const require = createRequire(import.meta.url);
298→    const pkg = require('../../package.json') as { version: string };
299→    return pkg.version;
300→  } catch {
301→    return 'unknown';
302→  }
303→}
304→
305→/**
306→ * Detect which AI coding tool data directories exist on this machine.
307→ * Checks directory existence only — never reads file contents.
308→ */
309→function detectProviders(): string[] {
310→  const home = os.homedir();
311→  const detected: string[] = [];
312→
313→  if (fs.existsSync(path.join(home, '.claude', 'projects'))) {
314→    detected.push('claude-code');
315→  }
316→
317→  const cursorStoragePaths = [
318→    path.join(home, 'Library', 'Application Support', 'Cursor', 'User', 'workspaceStorage'),
319→    path.join(home, '.config', 'Cursor', 'User', 'workspaceStorage'),
320→    path.join(home, 'AppData', 'Roaming', 'Cursor', 'User', 'workspaceStorage'),
321→  ];
322→  if (cursorStoragePaths.some((p) => fs.existsSync(p))) {
323→    detected.push('cursor');
324→  }
325→
326→  if (fs.existsSync(path.join(home, '.codex', 'sessions'))) {
327→    detected.push('codex-cli');
328→  }
329→
330→  if (fs.existsSync(path.join(home, '.copilot', 'session-state'))) {
331→    detected.push('copilot-cli');
332→  }
333→
334→  return detected;
335→}
336→
337→/**
338→ * Check if code-insights is registered as a Claude Code hook.
339→ */
340→function detectHook(): boolean {
341→  try {
342→    const settingsPath = path.join(os.homedir(), '.claude', 'settings.json');
343→    if (!fs.existsSync(settingsPath)) return false;
344→    const content = fs.readFileSync(settingsPath, 'utf-8');
345→    return content.includes('code-insights');
346→  } catch {
347→    return false;
348→  }
349→}
