225→/**
226→ * Analyze prompt quality for a session.
227→ */
228→export async function analyzePromptQuality(
229→  session: SessionData,
230→  messages: SQLiteMessageRow[],
231→  options?: AnalysisOptions
232→): Promise<AnalysisResult> {
233→  if (!isLLMConfigured()) {
234→    return {
235→      success: false,
236→      insights: [],
237→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
238→    };
239→  }
240→
241→  if (messages.length === 0) {
242→    return {
243→      success: false,
244→      insights: [],
245→      error: 'No messages found for this session.',
246→    };
247→  }
248→
249→  const userMessages = messages.filter(m => m.type === 'user');
250→  if (userMessages.length < 2) {
251→    return {
252→      success: false,
253→      insights: [],
254→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
255→    };
256→  }
257→
258→  try {
259→    const client = createLLMClient();
260→    const formattedMessages = formatMessagesForAnalysis(messages);
261→
262→    let analysisInput = formattedMessages;
263→    const estimatedTokens = client.estimateTokens(formattedMessages);
264→    if (estimatedTokens > MAX_INPUT_TOKENS) {
265→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
266→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
267→    }
268→
269→    const prompt = generatePromptQualityPrompt(
270→      session.project_name,
271→      analysisInput,
272→      messages.length
273→    );
274→
275→    options?.onProgress?.({ phase: 'analyzing' });
276→    const response = await client.chat([
277→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
278→      { role: 'user', content: prompt },
279→    ], { signal: options?.signal });
280→
281→    const parsed = parsePromptQualityResponse(response.content);
282→    if (!parsed.success) {
283→      return {
284→        success: false,
285→        insights: [],
286→        error: 'Failed to parse prompt quality analysis. Please try again.',
287→        error_type: parsed.error.error_type,
288→        response_length: parsed.error.response_length,
289→      };
290→    }
291→
292→    options?.onProgress?.({ phase: 'saving' });
293→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
294→
295→    // Save new insight, then delete old prompt_quality insights
296→    saveInsightsToDb([insight]);
297→    deleteSessionInsights(session.id, {
298→      includeOnlyTypes: ['prompt_quality'],
299→      excludeIds: [insight.id],
300→    });
301→
302→    return {
303→      success: true,
304→      insights: [insight],
305→      usage: response.usage ? {
306→        inputTokens: response.usage.inputTokens,
307→        outputTokens: response.usage.outputTokens,
308→      } : undefined,
309→    };
310→  } catch (error) {
311→    if (error instanceof Error && error.name === 'AbortError') {
312→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
313→    }
314→    return {
315→      success: false,
316→      insights: [],
317→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
318→      error_type: 'api_error',
319→    };
320→  }
321→}
322→
323→export interface RecurringInsightGroup {
324→  insightIds: string[];
325→  theme: string;
326→}
327→
328→export interface RecurringInsightResult {
329→  success: boolean;
330→  groups: RecurringInsightGroup[];
331→  updatedCount: number;
332→  error?: string;
333→  usage?: {
334→    inputTokens: number;
335→    outputTokens: number;
336→  };
337→}
338→
339→/**
340→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
341→ */
342→export async function findRecurringInsights(
343→  insights: Array<{
344→    id: string;
345→    type: string;
346→    title: string;
347→    summary: string;
348→    project_name: string;
349→    session_id: string;
350→  }>
351→): Promise<RecurringInsightResult> {
352→  if (!isLLMConfigured()) {
353→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
354→  }
355→
356→  const candidates = insights
357→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
358→    .slice(0, 200);
359→
360→  if (candidates.length < 2) {
361→    return {
362→      success: false,
363→      groups: [],
364→      updatedCount: 0,
365→      error: 'Need at least 2 non-summary insights to find patterns.',
366→    };
367→  }
368→
369→  try {
370→    const client = createLLMClient();
371→
372→    const insightData = candidates.map(i => ({
373→      id: i.id,
374→      type: i.type === 'technique' ? 'learning' : i.type,
375→      title: i.title,
376→      summary: i.summary.slice(0, 150),
377→      projectName: i.project_name,
378→      sessionId: i.session_id,
379→    }));
380→
381→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
382→
383→RULES:
384→- Only group insights that are genuinely about the same concept/topic
385→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
386→- A group must have at least 2 insights
387→- An insight can only belong to one group
388→- Provide a brief "theme" describing what the group shares
389→- If no recurring patterns exist, return an empty groups array
390→
391→INSIGHTS:
392→${JSON.stringify(insightData, null, 2)}
393→
394→Respond with valid JSON only:
395→{
396→  "groups": [
397→    {
398→      "insightIds": ["insight_abc", "insight_def"],
399→      "theme": "Brief description of the shared concept"
400→    }
401→  ]
402→}`;
403→
404→    const response = await client.chat([
405→      {
406→        role: 'system',
407→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
408→      },
409→      { role: 'user', content: prompt },
410→    ]);
411→
412→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
413→    if (!jsonMatch) {
414→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
415→    }
416→
417→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
418→    const groups = parsed.groups || [];
419→
420→    const validIds = new Set(candidates.map(i => i.id));
421→    const validGroups = groups
422→      .map(g => ({
423→        ...g,
424→        insightIds: g.insightIds.filter(id => validIds.has(id)),
425→      }))
426→      .filter(g => g.insightIds.length >= 2);
427→
428→    if (validGroups.length === 0) {
429→      return {
430→        success: true,
431→        groups: [],
432→        updatedCount: 0,
433→        usage: response.usage
434→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
435→          : undefined,
436→      };
437→    }
438→
439→    // Build bidirectional links
440→    const linkMap = new Map<string, string[]>();
441→    for (const group of validGroups) {
442→      for (const id of group.insightIds) {
443→        const others = group.insightIds.filter(otherId => otherId !== id);
444→        const existing = linkMap.get(id) || [];
445→        linkMap.set(id, [...new Set([...existing, ...others])]);
446→      }
447→    }
448→
449→    // Write links to SQLite
450→    const db = getDb();
451→    const updateLinks = db.prepare(
452→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
453→    );
454→
455→    for (const [insightId, linkedIds] of linkMap.entries()) {
456→      updateLinks.run(JSON.stringify(linkedIds), insightId);
457→    }
458→
459→    return {
460→      success: true,
461→      groups: validGroups,
462→      updatedCount: linkMap.size,
463→      usage: response.usage
464→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
465→        : undefined,
466→    };
467→  } catch (error) {
468→    return {
469→      success: false,
470→      groups: [],
471→      updatedCount: 0,
472→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
473→    };
474→  }
475→}
