 89→export interface ToolCall {
 90→  id: string;                   // tool_use_id from JSONL
 91→  name: string;
 92→  input: string;                // serialized JSON from CLI
 93→}
 94→
 95→export interface ToolResult {
 96→  toolUseId: string;            // References ToolCall.id
 97→  output: string;               // Truncated tool output
 98→}
 99→
100→export interface Message {
101→  id: string;
102→  session_id: string;
103→  type: 'user' | 'assistant' | 'system';
104→  content: string;
105→  thinking: string | null;
106→  tool_calls: string;           // JSON-encoded array from SQLite
107→  tool_results: string;         // JSON-encoded array from SQLite
108→  usage: string | null;         // JSON-encoded object from SQLite
109→  timestamp: string;            // ISO 8601
110→  parent_id: string | null;
