113→// Daily stats from /api/analytics/usage
114→export interface DailyStats {
115→  date: string;
116→  session_count: number;
117→  message_count: number;
118→  insight_count: number;
119→  total_tokens?: number;
120→  estimated_cost_usd?: number;
121→}
