147→  dashboardPort: number;
148→  provider?: 'openai' | 'anthropic' | 'gemini' | 'ollama';
149→  model?: string;
150→  apiKey?: string;      // masked by server before returning (first4...last4)
151→  baseUrl?: string;
152→}
