 1→import { clsx, type ClassValue } from 'clsx';
 2→import { twMerge } from 'tailwind-merge';
 3→import { format } from 'date-fns';
 4→import type { Session } from '@/lib/types';
 5→
 6→export function cn(...inputs: ClassValue[]) {
 7→  return twMerge(clsx(inputs));
 8→}
 9→
10→/**
11→ * Format a session duration in human-friendly units.
12→ * Examples: "45m", "5h 23m", "1d 2h"
13→ */
14→export function formatDuration(startedAt: Date, endedAt: Date): string {
15→  const totalMinutes = Math.round((endedAt.getTime() - startedAt.getTime()) / 60000);
16→  if (totalMinutes < 1) return '<1m';
17→  if (totalMinutes < 60) return `${totalMinutes}m`;
18→  const hours = Math.floor(totalMinutes / 60);
19→  const minutes = totalMinutes % 60;
20→  if (hours < 24) return minutes > 0 ? `${hours}h ${minutes}m` : `${hours}h`;
21→  const days = Math.floor(hours / 24);
22→  const remainingHours = hours % 24;
23→  return remainingHours > 0 ? `${days}d ${remainingHours}h` : `${days}d`;
24→}
25→
26→/**
27→ * Format a duration given in whole minutes into a human-friendly string.
28→ * Examples: "45m", "1h 30m", "2h"
29→ */
30→export function formatDurationMinutes(minutes: number): string {
31→  if (minutes < 60) return `${minutes}m`;
32→  const h = Math.floor(minutes / 60);
33→  const m = minutes % 60;
34→  return m > 0 ? `${h}h ${m}m` : `${h}h`;
35→}
36→
37→/**
38→ * Format a Claude model ID for display by stripping the 'claude-' prefix
39→ * and any trailing date suffix (e.g., '-20250929').
40→ */
41→export function formatModelName(model: string): string {
42→  return model.replace('claude-', '').replace(/-\d{8}$/, '');
43→}
44→
45→/**
46→ * Format a date range for display.
47→ * Same day: "Feb 12, 1:20 PM – 3:40 PM"
48→ * Multi-day: "Feb 12, 1:20 PM – Feb 13, 3:40 PM"
49→ */
50→export function formatDateRange(startedAt: Date, endedAt: Date): string {
51→  const sameDay = startedAt.toDateString() === endedAt.toDateString();
52→  if (sameDay) {
53→    return `${format(startedAt, 'MMM d, h:mm a')} – ${format(endedAt, 'h:mm a')}`;
54→  }
55→  return `${format(startedAt, 'MMM d, h:mm a')} – ${format(endedAt, 'MMM d, h:mm a')}`;
56→}
57→
58→/**
59→ * Format a token count with human-friendly units.
60→ * Examples: "1,234", "45.2K", "3.1M", "6.2B"
61→ */
62→export function formatTokenCount(tokens: number): string {
63→  if (tokens >= 1_000_000_000) return `${(tokens / 1_000_000_000).toFixed(1)}B`;
64→  if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
65→  if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
66→  return tokens.toLocaleString();
67→}
68→
69→/**
70→ * Get display title for a session with priority: custom_title > generated_title > summary > fallback
71→ */
72→export function getSessionTitle(session: Pick<Session, 'custom_title' | 'generated_title' | 'summary'>): string {
73→  return session.custom_title || session.generated_title || session.summary || 'Untitled Session';
74→}
