  1→import { useMemo, useState } from 'react';
  2→import { Link } from 'react-router';
  3→import { useDashboardStats } from '@/hooks/useAnalytics';
  4→import { useSessions } from '@/hooks/useSessions';
  5→import { useInsights } from '@/hooks/useInsights';
  6→import { useProjects } from '@/hooks/useProjects';
  7→import { StatsHero } from '@/components/dashboard/StatsHero';
  8→import { DashboardActivityChart } from '@/components/dashboard/DashboardActivityChart';
  9→import { ActivityFeed } from '@/components/dashboard/ActivityFeed';
 10→import { BulkAnalyzeButton } from '@/components/analysis/BulkAnalyzeButton';
 11→import { StatsHeroSkeleton } from '@/components/skeletons/StatsHeroSkeleton';
 12→import { ErrorCard } from '@/components/ErrorCard';
 13→import { Card, CardContent, CardHeader } from '@/components/ui/card';
 14→import { Skeleton } from '@/components/ui/skeleton';
 15→import type { DailyStats } from '@/lib/types';
 16→import { Sparkles, ArrowRight } from 'lucide-react';
 17→
 18→type DashboardRange = '7d' | '30d' | '90d' | 'all';
 19→
 20→function getGreeting(): string {
 21→  const hour = new Date().getHours();
 22→  if (hour < 12) return 'Good morning';
 23→  if (hour < 17) return 'Good afternoon';
 24→  return 'Good evening';
 25→}
 26→
 27→export default function DashboardPage() {
 28→  const [range, setRange] = useState<DashboardRange>('7d');
 29→
 30→  const { data: dashStats, isLoading: statsLoading, isError: statsError, refetch: refetchStats } = useDashboardStats(range);
 31→  const { data: sessions = [], isLoading: sessionsLoading, isError: sessionsError, refetch: refetchSessions } = useSessions({ limit: 500 });
 32→  const { data: insights = [], isLoading: insightsLoading } = useInsights();
 33→  const { data: projects = [] } = useProjects();
 34→
 35→  const loading = statsLoading || sessionsLoading || insightsLoading;
 36→  const hasError = statsError || sessionsError;
 37→
 38→  const todayLabel = new Date().toLocaleDateString(undefined, {
 39→    month: 'long',
 40→    day: 'numeric',
 41→  });
 42→
 43→  // Sessions not yet analyzed
 44→  const analyzedSessionIds = new Set(insights.map((i) => i.session_id));
 45→  const unanalyzedSessions = sessions.filter((s) => !analyzedSessionIds.has(s.id));
 46→
 47→  // Build daily stats for activity chart
 48→  const dailyStats: DailyStats[] = useMemo(() => {
 49→    const now = Date.now();
 50→    const rangeDays = range === '7d' ? 7 : range === '30d' ? 30 : range === '90d' ? 90 : Infinity;
 51→    const cutoff = rangeDays === Infinity ? 0 : now - rangeDays * 86_400_000;
 52→
 53→    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
 54→    for (const s of sessions) {
 55→      if (new Date(s.started_at).getTime() < cutoff) continue;
 56→      const date = s.started_at.slice(0, 10);
 57→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 58→      grouped[date].session_count++;
 59→    }
 60→    for (const i of insights) {
 61→      if (new Date(i.timestamp).getTime() < cutoff) continue;
 62→      const date = i.timestamp.slice(0, 10);
 63→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 64→      grouped[date].insight_count++;
 65→    }
 66→    return Object.entries(grouped)
 67→      .sort(([a], [b]) => a.localeCompare(b))
 68→      .map(([date, counts]) => ({
 69→        date,
 70→        session_count: counts.session_count,
 71→        message_count: 0,
 72→        insight_count: counts.insight_count,
 73→      }));
 74→  }, [sessions, insights, range]);
 75→
 76→  // Compute stats for hero — all from dashStats (range-filtered)
 77→  const totalTokens = dashStats
 78→    ? (dashStats.total_input_tokens ?? 0) +
 79→      (dashStats.total_output_tokens ?? 0) +
 80→      (dashStats.cache_creation_tokens ?? 0) +
 81→      (dashStats.cache_read_tokens ?? 0)
 82→    : 0;
 83→
 84→  const totalCost = dashStats?.estimated_cost_usd ?? 0;
 85→
 86→  const tokenBreakdown = dashStats
 87→    ? {
 88→        inputTokens: dashStats.total_input_tokens ?? 0,
 89→        outputTokens: dashStats.total_output_tokens ?? 0,
 90→        cacheCreationTokens: dashStats.cache_creation_tokens ?? 0,
 91→        cacheReadTokens: dashStats.cache_read_tokens ?? 0,
 92→      }
 93→    : undefined;
 94→
 95→  return (
 96→    <div className="p-4 lg:p-6 space-y-3">
 97→      {/* Greeting header */}
 98→      <div className="flex items-start justify-between">
 99→        <div>
100→          <h1 className="text-2xl font-bold">{getGreeting()}.</h1>
101→          {!loading && (
102→            <p className="text-muted-foreground text-sm mt-1 animate-in fade-in slide-in-from-bottom-2 duration-300">
103→              {sessions.length} session{sessions.length !== 1 ? 's' : ''} loaded
104→              {' '}&middot; {projects.length} project{projects.length !== 1 ? 's' : ''}
105→            </p>
106→          )}
107→        </div>
108→        <span className="text-sm text-muted-foreground">{todayLabel}</span>
109→      </div>
110→
111→      {/* Error state */}
112→      {hasError && !loading && (
113→        <ErrorCard
114→          message="Failed to load dashboard data"
115→          onRetry={() => { refetchStats(); refetchSessions(); }}
116→        />
117→      )}
118→
119→      {/* All-time stats hero */}
120→      {loading ? (
121→        <StatsHeroSkeleton />
122→      ) : (
123→        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
124→          <StatsHero
125→            totalSessions={dashStats?.session_count ?? sessions.length}
126→            totalMessages={dashStats?.total_messages ?? 0}
127→            totalToolCalls={dashStats?.total_tool_calls ?? 0}
128→            totalDurationMin={dashStats?.total_duration_min ?? 0}
129→            totalProjects={dashStats?.active_projects ?? projects.length}
130→            isExact={true}
131→            totalTokens={totalTokens > 0 ? totalTokens : undefined}
132→            totalCost={totalCost > 0 ? totalCost : undefined}
133→            tokenBreakdown={tokenBreakdown}
134→          />
135→        </div>
136→      )}
137→
138→      {/* Activity chart */}
139→      {loading ? (
140→        <Card>
141→          <CardHeader className="flex flex-row items-center justify-between pb-1">
142→            <Skeleton className="h-4 w-16" />
143→            <div className="flex gap-1">
144→              <Skeleton className="h-7 w-10 rounded" />
145→              <Skeleton className="h-7 w-10 rounded" />
146→              <Skeleton className="h-7 w-8 rounded" />
147→            </div>
148→          </CardHeader>
149→          <CardContent>
150→            <Skeleton className="h-[250px] w-full rounded" />
151→          </CardContent>
152→        </Card>
153→      ) : (
154→        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-150">
155→          <DashboardActivityChart data={dailyStats} range={range} onRangeChange={setRange} />
156→        </div>
157→      )}
158→
159→      {/* Needs Attention banner */}
160→      {unanalyzedSessions.length > 0 && (
161→        <Card className="border-amber-500/20 bg-amber-500/5 hover:shadow-md transition-shadow animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
162→          <CardContent className="flex items-center justify-between py-4">
163→            <div className="flex items-center gap-2">
164→              <Sparkles className="h-4 w-4 text-amber-600" />
165→              <div>
166→                <p className="text-sm font-medium">
167→                  {unanalyzedSessions.length} session{unanalyzedSessions.length !== 1 ? 's' : ''}{' '}
168→                  without analysis
169→                </p>
170→                <p className="text-xs text-muted-foreground">
171→                  Generate AI insights to extract learnings and decisions
172→                </p>
173→              </div>
174→            </div>
175→            <BulkAnalyzeButton sessions={unanalyzedSessions} />
176→          </CardContent>
177→        </Card>
178→      )}
179→
180→      {/* Unified activity feed */}
181→      <div
182→        className={
183→          loading ? '' : 'animate-in fade-in slide-in-from-bottom-2 duration-300 delay-300'
184→        }
185→      >
186→        <div className="flex items-center justify-between mb-2">
187→          <h2 className="text-sm font-semibold">Recent Activity</h2>
188→          <Link
189→            to="/sessions"
190→            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
191→          >
192→            View all
193→            <ArrowRight className="h-3 w-3" />
194→          </Link>
195→        </div>
196→        <Card>
197→          <CardContent className="px-4 py-2">
198→            {loading ? (
199→              <div className="divide-y divide-border">
200→                {[...Array(4)].map((_, i) => (
201→                  <div key={i} className="py-2">
202→                    <div className="flex items-center justify-between gap-2">
203→                      <div className="flex items-center gap-2 min-w-0">
204→                        <Skeleton className="h-6 w-6 rounded-md shrink-0" />
205→                        <Skeleton className="h-4 w-48" />
206→                        <Skeleton className="h-3.5 w-20" />
207→                      </div>
208→                      <Skeleton className="h-3.5 w-16 shrink-0" />
209→                    </div>
210→                  </div>
211→                ))}
212→              </div>
213→            ) : (
214→              <ActivityFeed sessions={sessions} insights={insights} limit={7} />
215→            )}
216→          </CardContent>
217→        </Card>
218→      </div>
219→    </div>
220→  );
221→}
