  1→import { Link } from 'react-router';
  2→import { formatDistanceToNow } from 'date-fns';
  3→import { MessageSquare, FileText, GitCommit, BookOpen, Target, Activity } from 'lucide-react';
  4→import { Badge } from '@/components/ui/badge';
  5→import { getSessionTitle } from '@/lib/utils';
  6→import { INSIGHT_TYPE_COLORS, SOURCE_TOOL_COLORS } from '@/lib/constants/colors';
  7→import type { Session, Insight, InsightType } from '@/lib/types';
  8→
  9→type FeedItem =
 10→  | { kind: 'session'; session: Session; timestamp: Date }
 11→  | { kind: 'insight'; insight: Insight; timestamp: Date };
 12→
 13→interface ActivityFeedProps {
 14→  sessions: Session[];
 15→  insights: Insight[];
 16→  limit?: number;
 17→}
 18→
 19→const insightTypeIcons: Record<InsightType, typeof FileText> = {
 20→  summary: FileText,
 21→  decision: GitCommit,
 22→  learning: BookOpen,
 23→  technique: BookOpen,
 24→  prompt_quality: Target,
 25→};
 26→
 27→const insightTypeLabels: Record<InsightType, string> = {
 28→  summary: 'Summary',
 29→  decision: 'Decision',
 30→  learning: 'Learning',
 31→  technique: 'Learning',
 32→  prompt_quality: 'Prompt Quality',
 33→};
 34→
 35→export function ActivityFeed({ sessions, insights, limit = 7 }: ActivityFeedProps) {
 36→  const feedItems: FeedItem[] = [
 37→    ...sessions.map((s) => ({ kind: 'session' as const, session: s, timestamp: new Date(s.started_at) })),
 38→    ...insights.map((i) => ({ kind: 'insight' as const, insight: i, timestamp: new Date(i.timestamp) })),
 39→  ]
 40→    .sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime())
 41→    .slice(0, limit);
 42→
 43→  if (feedItems.length === 0) {
 44→    return (
 45→      <div className="flex flex-col items-center justify-center py-8 gap-2 text-center">
 46→        <Activity className="h-8 w-8 text-muted-foreground/50" />
 47→        <p className="text-sm text-muted-foreground">No recent activity</p>
 48→        <p className="text-xs text-muted-foreground">Start an AI coding session and run code-insights sync to see it here.</p>
 49→      </div>
 50→    );
 51→  }
 52→
 53→  return (
 54→    <div className="space-y-0 divide-y divide-border">
 55→      {feedItems.map((item) =>
 56→        item.kind === 'session' ? (
 57→          <SessionFeedItem key={`s-${item.session.id}`} session={item.session} />
 58→        ) : (
 59→          <InsightFeedItem key={`i-${item.insight.id}`} insight={item.insight} />
 60→        )
 61→      )}
 62→    </div>
 63→  );
 64→}
 65→
 66→function SessionFeedItem({ session }: { session: Session }) {
 67→  const startedAt = new Date(session.started_at);
 68→  const endedAt = new Date(session.ended_at);
 69→  const durationMin = Math.round((endedAt.getTime() - startedAt.getTime()) / 60000);
 70→  const displayTitle = getSessionTitle(session);
 71→
 72→  return (
 73→    <Link to={`/sessions/${session.id}`} className="block group">
 74→      <div className="py-2 px-1 hover:bg-accent transition-all duration-200 rounded-sm">
 75→        <div className="flex items-center justify-between gap-2">
 76→          <div className="flex items-center gap-2 min-w-0">
 77→            <div className="shrink-0 h-6 w-6 rounded-md bg-primary/10 group-hover:bg-primary/15 flex items-center justify-center transition-colors">
 78→              <MessageSquare className="h-3 w-3 text-primary/70" />
 79→            </div>
 80→            <p className="text-sm font-medium line-clamp-1 group-hover:text-primary transition-colors min-w-0">
 81→              {displayTitle}
 82→            </p>
 83→            {session.source_tool && session.source_tool !== 'claude-code' && (
 84→              <Badge
 85→                variant="outline"
 86→                className={`text-xs capitalize shrink-0 ${SOURCE_TOOL_COLORS[session.source_tool] ?? 'bg-muted text-muted-foreground'}`}
 87→              >
 88→                {session.source_tool}
 89→              </Badge>
 90→            )}
 91→            <span className="text-xs text-muted-foreground shrink-0 whitespace-nowrap">
 92→              &middot; {session.message_count} msgs &middot; {durationMin}m
 93→            </span>
 94→          </div>
 95→          <span className="text-xs text-muted-foreground shrink-0">
 96→            {formatDistanceToNow(startedAt, { addSuffix: true })}
 97→          </span>
 98→        </div>
 99→      </div>
100→    </Link>
101→  );
102→}
103→
104→function InsightFeedItem({ insight }: { insight: Insight }) {
105→  const Icon = insightTypeIcons[insight.type];
106→  const colorClass = INSIGHT_TYPE_COLORS[insight.type];
107→  const label = insightTypeLabels[insight.type];
108→
109→  return (
110→    <Link to={`/sessions/${insight.session_id}`} className="block group">
111→      <div className="py-2 px-1 hover:bg-accent transition-all duration-200 rounded-sm">
112→        <div className="flex items-center justify-between gap-2">
113→          <div className="flex items-center gap-2 min-w-0">
114→            <div className={`shrink-0 h-6 w-6 rounded-md flex items-center justify-center transition-colors ${colorClass}`}>
115→              <Icon className="h-3 w-3" />
116→            </div>
117→            <p className="text-sm font-medium line-clamp-1 group-hover:text-primary transition-colors min-w-0">
118→              {insight.title}
119→            </p>
120→            <Badge variant="outline" className={`text-xs shrink-0 ${colorClass}`}>
121→              {label}
122→            </Badge>
123→          </div>
124→          <span className="text-xs text-muted-foreground shrink-0">
125→            {formatDistanceToNow(new Date(insight.timestamp), { addSuffix: true })}
126→          </span>
127→        </div>
128→      </div>
129→    </Link>
130→  );
131→}
