  1→// Analysis prompts and response parsers for LLM session analysis.
  2→// Ported from web repo (src/lib/llm/prompts.ts) with SQLite-aware message formatting.
  3→
  4→// SQLite row format for messages — snake_case with JSON-encoded arrays.
  5→// This matches the shape returned by server/src/routes/messages.ts.
  6→export interface SQLiteMessageRow {
  7→  id: string;
  8→  session_id: string;
  9→  type: 'user' | 'assistant' | 'system';
 10→  content: string;
 11→  thinking: string | null;
 12→  tool_calls: string;       // JSON-encoded ToolCall[]
 13→  tool_results: string;     // JSON-encoded ToolResult[]
 14→  usage: string | null;
 15→  timestamp: string;
 16→  parent_id: string | null;
 17→}
 18→
 19→interface ParsedToolCall {
 20→  name?: string;
 21→}
 22→
 23→interface ParsedToolResult {
 24→  output?: string;
 25→}
 26→
 27→/**
 28→ * Format SQLite message rows for LLM consumption.
 29→ * Handles snake_case fields and JSON-encoded tool_calls/tool_results.
 30→ */
 31→export function formatMessagesForAnalysis(messages: SQLiteMessageRow[]): string {
 32→  let userIndex = 0;
 33→  let assistantIndex = 0;
 34→
 35→  return messages
 36→    .map((m) => {
 37→      const role = m.type === 'user' ? 'User' : m.type === 'assistant' ? 'Assistant' : 'System';
 38→      const roleLabel = role === 'User'
 39→        ? `User#${userIndex++}`
 40→        : role === 'Assistant'
 41→          ? `Assistant#${assistantIndex++}`
 42→          : 'System';
 43→
 44→      // Parse JSON-encoded tool_calls
 45→      let toolCalls: ParsedToolCall[] = [];
 46→      try {
 47→        toolCalls = m.tool_calls ? (JSON.parse(m.tool_calls) as ParsedToolCall[]) : [];
 48→      } catch {
 49→        toolCalls = [];
 50→      }
 51→
 52→      // Parse JSON-encoded tool_results
 53→      let toolResults: ParsedToolResult[] = [];
 54→      try {
 55→        toolResults = m.tool_results ? (JSON.parse(m.tool_results) as ParsedToolResult[]) : [];
 56→      } catch {
 57→        toolResults = [];
 58→      }
 59→
 60→      const toolInfo = toolCalls.length > 0
 61→        ? `\n[Tools used: ${toolCalls.map(t => t.name || 'unknown').join(', ')}]`
 62→        : '';
 63→
 64→      // Include thinking content — capped at 1000 chars to stay within token budget
 65→      const thinkingInfo = m.thinking
 66→        ? `\n[Thinking: ${m.thinking.slice(0, 1000)}]`
 67→        : '';
 68→
 69→      // Include tool results for context — 200 chars per result
 70→      const resultInfo = toolResults.length > 0
 71→        ? `\n[Tool results: ${toolResults.map(r => (r.output || '').slice(0, 200)).join(' | ')}]`
 72→        : '';
 73→
 74→      return `### ${roleLabel}:\n${m.content}${thinkingInfo}${toolInfo}${resultInfo}`;
 75→    })
 76→    .join('\n\n');
 77→}
