158→export interface AnalysisResponse {
159→  summary: {
160→    title: string;
161→    content: string;
162→    bullets: string[];
163→  };
164→  decisions: Array<{
165→    title: string;
166→    content: string;
167→    reasoning: string;
168→    alternatives?: string[];
169→    confidence?: number;
170→    evidence?: string[];
171→  }>;
172→  learnings: Array<{
173→    title: string;
174→    content: string;
175→    context: string;
176→    confidence?: number;
177→    evidence?: string[];
