181→export interface ParseError {
182→  error_type: 'json_parse_error' | 'no_json_found' | 'invalid_structure';
183→  error_message: string;
184→  response_length: number;
185→  response_preview: string;
186→}
187→
188→function buildResponsePreview(text: string, head = 200, tail = 200): string {
189→  if (text.length <= head + tail + 20) return text;
190→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
191→}
192→
193→export type ParseResult<T> =
194→  | { success: true; data: T }
195→  | { success: false; error: ParseError };
196→
197→function extractJsonPayload(response: string): string | null {
198→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
199→  if (tagged?.[1]) return tagged[1].trim();
200→  const jsonMatch = response.match(/\{[\s\S]*\}/);
201→  return jsonMatch ? jsonMatch[0] : null;
202→}
203→
204→/**
205→ * Parse the LLM response into structured insights.
206→ */
207→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
208→  const response_length = response.length;
209→
210→  const preview = buildResponsePreview(response);
211→
212→  const jsonPayload = extractJsonPayload(response);
213→  if (!jsonPayload) {
214→    console.error('No JSON found in analysis response');
215→    return {
216→      success: false,
217→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
218→    };
219→  }
220→
221→  let parsed: AnalysisResponse;
222→  try {
223→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
224→  } catch (err) {
225→    const msg = err instanceof Error ? err.message : String(err);
226→    console.error('Failed to parse analysis response:', err);
227→    return {
228→      success: false,
229→      error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
230→    };
231→  }
232→
233→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
234→    console.error('Invalid analysis response structure');
235→    return {
236→      success: false,
237→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
238→    };
239→  }
240→
241→  parsed.decisions = parsed.decisions || [];
242→  parsed.learnings = parsed.learnings || [];
243→
244→  return { success: true, data: parsed };
245→}
