249→export const PROMPT_QUALITY_SYSTEM_PROMPT = `You are an expert at analyzing how effectively humans communicate with AI coding assistants. Your task is to review a conversation between a user and Claude Code, and evaluate the user's prompting efficiency.
250→
251→You will identify:
252→1. **Wasted turns**: User messages that led to clarifications, corrections, or repeated instructions because the original prompt was unclear, missing context, or too vague.
253→2. **Anti-patterns**: Recurring bad habits in the user's prompting style.
254→3. **Efficiency score**: A 0-100 rating of how optimally the user communicated.
255→4. **Actionable tips**: Specific improvements the user can make.
256→
257→Guidelines:
258→- Focus on USER messages only — don't critique the assistant's responses
259→- A "wasted turn" is when the user had to send a follow-up message to clarify, correct, or repeat something that could have been included in the original prompt
260→- Only mark a wasted turn if the assistant explicitly asked for clarification or corrected a misunderstanding
261→- Common anti-patterns: vague instructions, missing file paths, not providing error messages, incomplete requirements, repeated instructions, not specifying what "it" refers to
262→- Be constructive, not judgmental — the goal is to help users improve
263→- Consider the context: some clarification exchanges are normal and expected
264→- A score of 100 means every user message was perfectly clear and complete
265→- A score of 50 means about half the messages could have been more efficient
266→
267→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
268→
269→export function generatePromptQualityPrompt(
270→  projectName: string,
271→  formattedMessages: string,
272→  messageCount: number
273→): string {
274→  return `Analyze the user's prompting efficiency in this AI coding session.
275→
276→Project: ${projectName}
277→Total messages: ${messageCount}
278→
279→--- CONVERSATION ---
280→${formattedMessages}
281→--- END CONVERSATION ---
282→
283→Evaluate the user's prompting quality and respond with this JSON format:
284→{
285→  "efficiencyScore": 75,
286→  "potentialMessageReduction": 3,
287→  "overallAssessment": "2-3 sentence summary of the user's prompting style and efficiency",
288→  "wastedTurns": [
289→    {
290→      "messageIndex": 5,
291→      "reason": "Missing context — didn't specify which file to modify",
292→      "suggestedRewrite": "A better version of the user's original message that would have avoided the follow-up"
293→    }
294→  ],
295→  "antiPatterns": [
296→    {
297→      "name": "Vague Instructions",
298→      "count": 3,
299→      "examples": ["fix it", "make it work", "do the thing"]
300→    }
301→  ],
302→  "tips": [
303→    "Always include file paths when asking to modify code",
304→    "Provide error messages verbatim when reporting bugs"
305→  ]
306→}
307→
308→Rules:
309→- messageIndex refers to the 0-based index of the USER message, as labeled in the conversation (e.g., User#0)
310→- Only include genuinely wasted turns, not normal back-and-forth
311→- Tips should be specific and actionable, not generic; include the relevant user message index in parentheses
312→- If the user prompted well, say so — don't manufacture issues
313→- potentialMessageReduction is how many fewer messages the session could have taken with better prompts
314→
315→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
316→}
317→
318→export interface WastedTurn {
319→  messageIndex: number;
320→  reason: string;
321→  suggestedRewrite: string;
322→}
323→
324→export interface AntiPattern {
325→  name: string;
326→  count: number;
327→  examples: string[];
328→}
329→
330→export interface PromptQualityResponse {
331→  efficiencyScore: number;
332→  potentialMessageReduction: number;
333→  overallAssessment: string;
334→  wastedTurns: WastedTurn[];
335→  antiPatterns: AntiPattern[];
336→  tips: string[];
337→}
338→
339→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
340→  const response_length = response.length;
341→
342→  const preview = buildResponsePreview(response);
343→
344→  const jsonPayload = extractJsonPayload(response);
345→  if (!jsonPayload) {
346→    console.error('No JSON found in prompt quality response');
347→    return {
348→      success: false,
349→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
350→    };
351→  }
352→
353→  let parsed: PromptQualityResponse;
354→  try {
355→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
356→  } catch (err) {
357→    const msg = err instanceof Error ? err.message : String(err);
358→    console.error('Failed to parse prompt quality response:', err);
359→    return {
360→      success: false,
361→      error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
362→    };
363→  }
364→
365→  if (typeof parsed.efficiencyScore !== 'number') {
366→    console.error('Invalid prompt quality response: missing efficiencyScore');
367→    return {
368→      success: false,
369→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiencyScore field', response_length, response_preview: preview },
370→    };
371→  }
372→
373→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
374→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
375→  parsed.overallAssessment = parsed.overallAssessment || '';
376→  parsed.wastedTurns = parsed.wastedTurns || [];
377→  parsed.antiPatterns = parsed.antiPatterns || [];
378→  parsed.tips = parsed.tips || [];
379→
380→  return { success: true, data: parsed };
381→}
