188→function buildResponsePreview(text: string, head = 200, tail = 200): string {
189→  if (text.length <= head + tail + 20) return text;
190→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
191→}
