193→export type ParseResult<T> =
194→  | { success: true; data: T }
195→  | { success: false; error: ParseError };
196→
197→function extractJsonPayload(response: string): string | null {
198→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
199→  if (tagged?.[1]) return tagged[1].trim();
200→  const jsonMatch = response.match(/\{[\s\S]*\}/);
201→  return jsonMatch ? jsonMatch[0] : null;
202→}
