227→/**
228→ * Analyze prompt quality for a session.
229→ */
230→export async function analyzePromptQuality(
231→  session: SessionData,
232→  messages: SQLiteMessageRow[],
233→  options?: AnalysisOptions
234→): Promise<AnalysisResult> {
235→  if (!isLLMConfigured()) {
236→    return {
237→      success: false,
238→      insights: [],
239→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
240→    };
241→  }
242→
243→  if (messages.length === 0) {
244→    return {
245→      success: false,
246→      insights: [],
247→      error: 'No messages found for this session.',
248→    };
249→  }
250→
251→  const userMessages = messages.filter(m => m.type === 'user');
252→  if (userMessages.length < 2) {
253→    return {
254→      success: false,
255→      insights: [],
256→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
257→    };
258→  }
259→
260→  try {
261→    const client = createLLMClient();
262→    const formattedMessages = formatMessagesForAnalysis(messages);
263→
264→    let analysisInput = formattedMessages;
265→    const estimatedTokens = client.estimateTokens(formattedMessages);
266→    if (estimatedTokens > MAX_INPUT_TOKENS) {
267→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
268→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
269→    }
270→
271→    const prompt = generatePromptQualityPrompt(
272→      session.project_name,
273→      analysisInput,
274→      messages.length
275→    );
276→
277→    options?.onProgress?.({ phase: 'analyzing' });
278→    const response = await client.chat([
279→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
280→      { role: 'user', content: prompt },
281→    ], { signal: options?.signal });
282→
283→    const parsed = parsePromptQualityResponse(response.content);
284→    if (!parsed.success) {
285→      return {
286→        success: false,
287→        insights: [],
288→        error: 'Failed to parse prompt quality analysis. Please try again.',
289→        error_type: parsed.error.error_type,
290→        response_length: parsed.error.response_length,
291→        response_preview: parsed.error.response_preview,
292→      };
293→    }
294→
295→    options?.onProgress?.({ phase: 'saving' });
296→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
297→
298→    // Save new insight, then delete old prompt_quality insights
299→    saveInsightsToDb([insight]);
300→    deleteSessionInsights(session.id, {
301→      includeOnlyTypes: ['prompt_quality'],
302→      excludeIds: [insight.id],
303→    });
304→
305→    return {
306→      success: true,
307→      insights: [insight],
308→      usage: response.usage ? {
309→        inputTokens: response.usage.inputTokens,
310→        outputTokens: response.usage.outputTokens,
311→      } : undefined,
312→    };
313→  } catch (error) {
314→    if (error instanceof Error && error.name === 'AbortError') {
315→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
316→    }
317→    return {
318→      success: false,
319→      insights: [],
320→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
321→      error_type: 'api_error',
322→    };
323→  }
324→}
