342→/**
343→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
344→ */
345→export async function findRecurringInsights(
346→  insights: Array<{
347→    id: string;
348→    type: string;
349→    title: string;
350→    summary: string;
351→    project_name: string;
352→    session_id: string;
353→  }>
354→): Promise<RecurringInsightResult> {
355→  if (!isLLMConfigured()) {
356→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
357→  }
358→
359→  const candidates = insights
360→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
361→    .slice(0, 200);
362→
363→  if (candidates.length < 2) {
364→    return {
365→      success: false,
366→      groups: [],
367→      updatedCount: 0,
368→      error: 'Need at least 2 non-summary insights to find patterns.',
369→    };
370→  }
371→
372→  try {
373→    const client = createLLMClient();
374→
375→    const insightData = candidates.map(i => ({
376→      id: i.id,
377→      type: i.type === 'technique' ? 'learning' : i.type,
378→      title: i.title,
379→      summary: i.summary.slice(0, 150),
380→      projectName: i.project_name,
381→      sessionId: i.session_id,
382→    }));
383→
384→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
385→
386→RULES:
387→- Only group insights that are genuinely about the same concept/topic
388→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
389→- A group must have at least 2 insights
390→- An insight can only belong to one group
391→- Provide a brief "theme" describing what the group shares
392→- If no recurring patterns exist, return an empty groups array
393→
394→INSIGHTS:
395→${JSON.stringify(insightData, null, 2)}
396→
397→Respond with valid JSON only:
398→{
399→  "groups": [
400→    {
401→      "insightIds": ["insight_abc", "insight_def"],
402→      "theme": "Brief description of the shared concept"
403→    }
404→  ]
405→}`;
406→
407→    const response = await client.chat([
408→      {
409→        role: 'system',
410→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
411→      },
412→      { role: 'user', content: prompt },
413→    ]);
414→
415→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
416→    if (!jsonMatch) {
417→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
418→    }
419→
420→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
421→    const groups = parsed.groups || [];
422→
423→    const validIds = new Set(candidates.map(i => i.id));
424→    const validGroups = groups
425→      .map(g => ({
426→        ...g,
427→        insightIds: g.insightIds.filter(id => validIds.has(id)),
428→      }))
429→      .filter(g => g.insightIds.length >= 2);
430→
431→    if (validGroups.length === 0) {
432→      return {
433→        success: true,
434→        groups: [],
435→        updatedCount: 0,
436→        usage: response.usage
437→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
438→          : undefined,
439→      };
440→    }
441→
442→    // Build bidirectional links
443→    const linkMap = new Map<string, string[]>();
444→    for (const group of validGroups) {
445→      for (const id of group.insightIds) {
446→        const others = group.insightIds.filter(otherId => otherId !== id);
447→        const existing = linkMap.get(id) || [];
448→        linkMap.set(id, [...new Set([...existing, ...others])]);
449→      }
450→    }
451→
452→    // Write links to SQLite
453→    const db = getDb();
454→    const updateLinks = db.prepare(
455→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
456→    );
457→
458→    for (const [insightId, linkedIds] of linkMap.entries()) {
459→      updateLinks.run(JSON.stringify(linkedIds), insightId);
460→    }
461→
462→    return {
463→      success: true,
464→      groups: validGroups,
465→      updatedCount: linkMap.size,
466→      usage: response.usage
467→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
468→        : undefined,
469→    };
470→  } catch (error) {
471→    return {
472→      success: false,
473→      groups: [],
474→      updatedCount: 0,
475→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
476→    };
477→  }
478→}
