481→
482→function chunkMessages(
483→  messages: SQLiteMessageRow[],
484→  estimateTokens: (text: string) => number
485→): SQLiteMessageRow[][] {
486→  const chunks: SQLiteMessageRow[][] = [];
487→  let currentChunk: SQLiteMessageRow[] = [];
488→  let currentTokens = 0;
489→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
490→
491→  for (const message of messages) {
492→    let toolResults: Array<{ output?: string }> = [];
493→    try {
494→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
495→    } catch {
496→      toolResults = [];
497→    }
498→
499→    const messageText = [
500→      message.content,
501→      message.thinking?.slice(0, 1000) ?? '',
502→      ...toolResults.map(r => (r.output || '').slice(0, 200)),
503→    ].join(' ');
504→    const messageTokens = estimateTokens(messageText);
505→
506→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
507→      chunks.push(currentChunk);
508→      currentChunk = [];
509→      currentTokens = 0;
510→    }
511→
512→    currentChunk.push(message);
513→    currentTokens += messageTokens;
514→  }
515→
516→  if (currentChunk.length > 0) {
517→    chunks.push(currentChunk);
518→  }
519→
520→  return chunks;
521→}
