523→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
524→  if (responses.length === 0) {
525→    return {
526→      summary: { title: 'Analysis failed', content: '', bullets: [] },
527→      decisions: [],
528→      learnings: [],
529→    };
530→  }
531→
532→  if (responses.length === 1) return responses[0];
533→
534→  const merged: AnalysisResponse = {
535→    summary: responses[0].summary,
536→    decisions: [],
537→    learnings: [],
538→  };
539→
540→  for (const response of responses) {
541→    merged.decisions.push(...response.decisions);
542→    merged.learnings.push(...response.learnings);
543→  }
544→
545→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
546→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
547→
548→  return merged;
549→}
