 42→  // Filter by selected range
 43→  const cutoff = useMemo(() => {
 44→    if (range === 'all') return 0;
 45→    const days = range === '7d' ? 7 : range === '30d' ? 30 : 90;
 46→    return Date.now() - days * 86_400_000;
 47→  }, [range]);
 48→
 49→  const filteredSessions = useMemo(
 50→    () => cutoff === 0 ? sessions : sessions.filter((s) => new Date(s.started_at).getTime() >= cutoff),
 51→    [sessions, cutoff]
 52→  );
 53→  const filteredInsights = useMemo(
 54→    () => cutoff === 0 ? insights : insights.filter((i) => new Date(i.timestamp).getTime() >= cutoff),
 55→    [insights, cutoff]
