 58→  // Build daily stats from filtered sessions
 59→  const dailyStats: DailyStats[] = useMemo(() => {
 60→    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
 61→    for (const s of filteredSessions) {
 62→      const date = s.started_at.slice(0, 10);
 63→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 64→      grouped[date].session_count++;
 65→    }
 66→    for (const i of filteredInsights) {
 67→      const date = i.timestamp.slice(0, 10);
 68→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 69→      grouped[date].insight_count++;
 70→    }
 71→    return Object.entries(grouped)
 72→      .sort(([a], [b]) => a.localeCompare(b))
 73→      .map(([date, counts]) => ({
 74→        date,
 75→        session_count: counts.session_count,
 76→        message_count: 0,
 77→        insight_count: counts.insight_count,
 78→      }));
 79→  }, [filteredSessions, filteredInsights]);
 80→
 81→  // Insight type breakdown
