 95→        projectName: string;
 96→        sessionCount: number;
 97→        insightCounts: { summary: number; decision: number; learning: number; prompt_quality: number };
 98→        totalInputTokens: number;
 99→        totalOutputTokens: number;
100→        estimatedCostUsd: number;
101→      }
102→    > = {};
103→
104→    for (const s of filteredSessions) {
105→      if (!statsMap[s.project_id]) {
106→        statsMap[s.project_id] = {
107→          projectId: s.project_id,
108→          projectName: s.project_name,
109→          sessionCount: 0,
110→          insightCounts: { summary: 0, decision: 0, learning: 0, prompt_quality: 0 },
111→          totalInputTokens: 0,
112→          totalOutputTokens: 0,
113→          estimatedCostUsd: 0,
114→        };
115→      }
116→      statsMap[s.project_id].sessionCount++;
117→      statsMap[s.project_id].totalInputTokens += s.total_input_tokens ?? 0;
118→      statsMap[s.project_id].totalOutputTokens += s.total_output_tokens ?? 0;
119→      statsMap[s.project_id].estimatedCostUsd += s.estimated_cost_usd ?? 0;
120→    }
121→
122→    for (const i of filteredInsights) {
123→      if (statsMap[i.project_id]) {
124→        const type = i.type === 'technique' ? 'learning' : i.type;
125→        if (type in statsMap[i.project_id].insightCounts) {
