 37→function formatCompact(n: number): string {
 38→  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
 39→  if (n >= 10_000) return `${(n / 1_000).toFixed(1)}k`;
 40→  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
 41→  return n.toString();
 42→}
