158→/**
159→ * Capture an exception in PostHog. Never throws — telemetry must never break the CLI.
160→ * Respects the same opt-out as trackEvent.
161→ *
162→ * @param error - The caught error (or unknown value)
163→ * @param properties - Additional context properties (provider, model, etc.)
164→ */
165→export function captureError(error: unknown, properties?: Record<string, unknown>): void {
166→  const ph = getPostHogClient();
167→  if (!ph) return;
168→
169→  try {
170→    const { error_type, error_message } = classifyError(error);
171→    const exceptionType = error instanceof Error ? error.constructor.name : error_type;
172→    ph.capture({
173→      distinctId: getStableMachineId(),
174→      event: '$exception',
175→      properties: {
176→        $exception_message: error_message,
177→        $exception_type: exceptionType,
178→        $exception_list: [
179→          {
180→            type: exceptionType,
181→            value: error_message,
182→            mechanism: { type: 'generic', handled: true },
183→          },
184→        ],
185→        ...(properties ?? {}),
186→      },
187→    });
188→  } catch {
189→    // Swallow all errors — telemetry failures are silent
190→  }
191→}
