 93→export async function analyzeSession(
 94→  session: SessionData,
 95→  messages: SQLiteMessageRow[],
 96→  options?: AnalysisOptions
 97→): Promise<AnalysisResult> {
 98→  if (!isLLMConfigured()) {
 99→    return {
100→      success: false,
101→      insights: [],
102→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
103→    };
104→  }
105→
106→  if (messages.length === 0) {
107→    return {
108→      success: false,
109→      insights: [],
110→      error: 'No messages found for this session.',
111→    };
112→  }
113→
114→  try {
115→    const client = createLLMClient();
116→    const formattedMessages = formatMessagesForAnalysis(messages);
117→    const estimatedTokens = client.estimateTokens(formattedMessages);
118→
119→    let analysisResponse: AnalysisResponse;
120→    let totalInputTokens = 0;
121→    let totalOutputTokens = 0;
122→
123→    if (estimatedTokens > MAX_INPUT_TOKENS) {
124→      // Chunk the messages and analyze separately
125→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
126→      const chunkResponses: AnalysisResponse[] = [];
127→      const totalChunks = chunks.length;
128→
129→      for (let i = 0; i < chunks.length; i++) {
130→        const chunk = chunks[i];
131→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
132→
133→        const chunkFormatted = formatMessagesForAnalysis(chunk);
134→        const prompt = generateSessionAnalysisPrompt(
135→          session.project_name,
136→          session.summary,
137→          chunkFormatted
138→        );
139→
140→        const response = await client.chat([
141→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
142→          { role: 'user', content: prompt },
143→        ], { signal: options?.signal });
144→
145→        if (response.usage) {
146→          totalInputTokens += response.usage.inputTokens;
147→          totalOutputTokens += response.usage.outputTokens;
148→        }
149→
150→        const parsed = parseAnalysisResponse(response.content);
151→        if (parsed.success) chunkResponses.push(parsed.data);
152→      }
153→
154→      if (chunkResponses.length === 0) {
155→        return {
156→          success: false,
157→          insights: [],
158→          error: 'All chunks failed to parse LLM response',
159→          error_type: 'json_parse_error',
160→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
161→        };
162→      }
163→
164→      analysisResponse = mergeAnalysisResponses(chunkResponses);
165→    } else {
166→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
167→      const prompt = generateSessionAnalysisPrompt(
168→        session.project_name,
169→        session.summary,
170→        formattedMessages
171→      );
172→
173→      const response = await client.chat([
174→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
175→        { role: 'user', content: prompt },
176→      ], { signal: options?.signal });
177→
178→      if (response.usage) {
179→        totalInputTokens = response.usage.inputTokens;
180→        totalOutputTokens = response.usage.outputTokens;
181→      }
182→
183→      const parsed = parseAnalysisResponse(response.content);
184→      if (!parsed.success) {
185→        return {
186→          success: false,
187→          insights: [],
188→          error: 'Failed to parse LLM response. Please try again.',
189→          error_type: parsed.error.error_type,
190→          response_length: parsed.error.response_length,
191→          response_preview: parsed.error.response_preview,
192→        };
193→      }
194→
195→      analysisResponse = parsed.data;
196→    }
197→
198→    options?.onProgress?.({ phase: 'saving' });
199→    const insights = convertToInsightRows(analysisResponse, session);
200→
201→    // Save new insights first, then delete old non-prompt-quality insights
202→    // (safe order: if save fails, old data is preserved)
203→    saveInsightsToDb(insights);
204→    deleteSessionInsights(session.id, {
205→      excludeTypes: ['prompt_quality'],
206→      excludeIds: insights.map(i => i.id),
207→    });
208→
209→    return {
210→      success: true,
211→      insights,
212→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
213→    };
214→  } catch (error) {
215→    if (error instanceof Error && error.name === 'AbortError') {
216→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
217→    }
218→    return {
219→      success: false,
220→      insights: [],
221→      error: error instanceof Error ? error.message : 'Analysis failed',
222→      error_type: 'api_error',
223→    };
224→  }
225→}
