230→export async function analyzePromptQuality(
231→  session: SessionData,
232→  messages: SQLiteMessageRow[],
233→  options?: AnalysisOptions
234→): Promise<AnalysisResult> {
235→  if (!isLLMConfigured()) {
236→    return {
237→      success: false,
238→      insights: [],
239→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
240→    };
241→  }
242→
243→  if (messages.length === 0) {
244→    return {
245→      success: false,
246→      insights: [],
247→      error: 'No messages found for this session.',
248→    };
249→  }
250→
251→  const userMessages = messages.filter(m => m.type === 'user');
252→  if (userMessages.length < 2) {
