313→  } catch (error) {
314→    if (error instanceof Error && error.name === 'AbortError') {
315→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
316→    }
317→    return {
318→      success: false,
319→      insights: [],
