480→// --- Internal helpers ---
481→
482→function chunkMessages(
483→  messages: SQLiteMessageRow[],
484→  estimateTokens: (text: string) => number
485→): SQLiteMessageRow[][] {
486→  const chunks: SQLiteMessageRow[][] = [];
487→  let currentChunk: SQLiteMessageRow[] = [];
488→  let currentTokens = 0;
489→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
490→
491→  for (const message of messages) {
492→    let toolResults: Array<{ output?: string }> = [];
493→    try {
494→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
495→    } catch {
496→      toolResults = [];
497→    }
498→
499→    const messageText = [
500→      message.content,
501→      message.thinking?.slice(0, 1000) ?? '',
502→      ...toolResults.map(r => (r.output || '').slice(0, 200)),
503→    ].join(' ');
504→    const messageTokens = estimateTokens(messageText);
505→
506→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
507→      chunks.push(currentChunk);
508→      currentChunk = [];
509→      currentTokens = 0;
510→    }
511→
512→    currentChunk.push(message);
513→    currentTokens += messageTokens;
514→  }
515→
516→  if (currentChunk.length > 0) {
517→    chunks.push(currentChunk);
518→  }
519→
520→  return chunks;
521→}
522→
523→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
524→  if (responses.length === 0) {
525→    return {
526→      summary: { title: 'Analysis failed', content: '', bullets: [] },
527→      decisions: [],
528→      learnings: [],
529→    };
530→  }
531→
532→  if (responses.length === 1) return responses[0];
533→
534→  const merged: AnalysisResponse = {
535→    summary: responses[0].summary,
536→    decisions: [],
537→    learnings: [],
538→  };
539→
540→  for (const response of responses) {
541→    merged.decisions.push(...response.decisions);
542→    merged.learnings.push(...response.learnings);
543→  }
544→
545→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
546→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
547→
548→  return merged;
549→}
550→
551→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
552→  const seen = new Set<string>();
553→  return items.filter((item) => {
554→    const normalized = item.title.toLowerCase().trim();
555→    if (seen.has(normalized)) return false;
556→    seen.add(normalized);
557→    return true;
558→  });
559→}
