670→/**
671→ * Write insight rows to SQLite using prepared statements.
672→ */
673→function saveInsightsToDb(insights: InsightRow[]): void {
674→  const db = getDb();
675→  const insert = db.prepare(`
676→    INSERT OR REPLACE INTO insights (
677→      id, session_id, project_id, project_name, type, title, content,
678→      summary, bullets, confidence, source, metadata, timestamp,
679→      created_at, scope, analysis_version
680→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
681→  `);
682→
683→  const insertMany = db.transaction((rows: InsightRow[]) => {
684→    for (const row of rows) {
685→      insert.run(
686→        row.id,
687→        row.session_id,
688→        row.project_id,
689→        row.project_name,
690→        row.type,
691→        row.title,
692→        row.content,
693→        row.summary,
694→        row.bullets,
695→        row.confidence,
696→        row.source,
697→        row.metadata,
698→        row.timestamp,
699→        row.created_at,
700→        row.scope,
701→        row.analysis_version,
702→      );
703→    }
704→  });
705→
706→  insertMany(insights);
707→}
