709→interface DeleteOptions {
710→  excludeTypes?: string[];
711→  includeOnlyTypes?: string[];
712→  excludeIds?: string[];
713→}
714→
715→/**
716→ * Delete insights for a session, with optional type and ID exclusions.
717→ */
718→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
719→  const db = getDb();
720→  const conditions: string[] = ['session_id = ?'];
721→  const params: (string | number)[] = [sessionId];
722→
723→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
724→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
725→    params.push(...opts.excludeTypes);
726→  }
727→
728→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
729→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
730→    params.push(...opts.includeOnlyTypes);
731→  }
732→
733→  if (opts.excludeIds && opts.excludeIds.length > 0) {
734→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
735→    params.push(...opts.excludeIds);
736→  }
737→
738→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
739→}
