// HTTP client for the Hono API server.
// Base URL is relative in production (SPA served by the same server).
// In Vite dev mode, the proxy forwards /api -> localhost:7890.

import type { Project, Session, Message, Insight, DashboardStats, LLMConfig } from '@/lib/types';

const BASE = '/api';

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  // Only set Content-Type when a body is present — setting it on GET requests
  // adds unnecessary headers and can confuse some intermediaries.
  const headers: Record<string, string> = { ...(init?.headers as Record<string, string>) };
  if (init?.body) {
    headers['Content-Type'] = 'application/json';
  }
  const res = await fetch(`${BASE}${path}`, { ...init, headers });
  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText);
    throw new Error(`API ${res.status}: ${text}`);
  }
  return res.json() as Promise<T>;
}

// ── Projects ──────────────────────────────────────────────────────────────────

export function fetchProjects() {
  return request<{ projects: Project[] }>('/projects');
}

export function fetchProject(id: string) {
  return request<{ project: Project }>(`/projects/${id}`);
}

// ── Sessions ──────────────────────────────────────────────────────────────────

export function fetchSessions(params?: {
  projectId?: string;
  sourceTool?: string;
  limit?: number;
  offset?: number;
}) {
  const q = new URLSearchParams();
  if (params?.projectId) q.set('projectId', params.projectId);
  if (params?.sourceTool) q.set('sourceTool', params.sourceTool);
  if (params?.limit !== undefined) q.set('limit', String(params.limit));
  if (params?.offset !== undefined) q.set('offset', String(params.offset));
  const qs = q.toString() ? `?${q.toString()}` : '';
  return request<{ sessions: Session[] }>(`/sessions${qs}`);
}

export function fetchSession(id: string) {
  return request<{ session: Session }>(`/sessions/${id}`);
}

export function patchSession(id: string, body: { customTitle: string }) {
  return request<{ ok: boolean }>(`/sessions/${id}`, {
    method: 'PATCH',
    body: JSON.stringify(body),
  });
}

// ── Messages ──────────────────────────────────────────────────────────────────

export function fetchMessages(sessionId: string, params?: { limit?: number; offset?: number }) {
  const q = new URLSearchParams();
  if (params?.limit !== undefined) q.set('limit', String(params.limit));
  if (params?.offset !== undefined) q.set('offset', String(params.offset));
  const qs = q.toString() ? `?${q.toString()}` : '';
  return request<{ messages: Message[] }>(`/messages/${sessionId}${qs}`);
}

// ── Insights ──────────────────────────────────────────────────────────────────

export function fetchInsights(params?: {
  projectId?: string;
  sessionId?: string;
  type?: string;
}) {
  const q = new URLSearchParams();
  if (params?.projectId) q.set('projectId', params.projectId);
  if (params?.sessionId) q.set('sessionId', params.sessionId);
  if (params?.type) q.set('type', params.type);
  const qs = q.toString() ? `?${q.toString()}` : '';
  return request<{ insights: Insight[] }>(`/insights${qs}`);
}

export function deleteInsight(id: string) {
  return request<{ ok: boolean }>(`/insights/${id}`, { method: 'DELETE' });
}

// ── Analytics ─────────────────────────────────────────────────────────────────

export function fetchDashboardStats(range: '7d' | '30d' | '90d' | 'all' = '7d') {
  return request<{ range: string; stats: DashboardStats }>(`/analytics/dashboard?range=${range}`);
}

export function fetchUsageStats() {
  return request<{ stats: unknown }>('/analytics/usage');
}

// ── Analysis (Phase 4) ────────────────────────────────────────────────────────

export interface AnalysisApiResult {
  success: boolean;
  insights?: Array<{ id: string; type: string; title: string }>;
  error?: string;
  usage?: { inputTokens: number; outputTokens: number };
}

export function analyzeSession(sessionId: string) {
  return request<AnalysisApiResult>('/analysis/session', {
    method: 'POST',
    body: JSON.stringify({ sessionId }),
  });
}

// ── Config ────────────────────────────────────────────────────────────────────

export function fetchLlmConfig() {
  return request<LLMConfig>('/config/llm');
}

export function saveLlmConfig(body: {
  dashboardPort?: number;
  provider?: string;
  model?: string;
  apiKey?: string;
  baseUrl?: string;
}) {
  return request<{ ok: boolean }>('/config/llm', {
    method: 'PUT',
    body: JSON.stringify(body),
  });
}

export function testLlmConfig(body?: {
  provider?: string;
  model?: string;
  apiKey?: string;
  baseUrl?: string;
}) {
  return request<{ success: boolean; error?: string }>('/config/llm/test', {
    method: 'POST',
    body: JSON.stringify(body ?? {}),
  });
}

export function fetchOllamaModels(baseUrl?: string) {
  const qs = baseUrl ? `?baseUrl=${encodeURIComponent(baseUrl)}` : '';
  return request<{ models: Array<{ name: string; size: number; modifiedAt: string }> }>(
    `/config/llm/ollama-models${qs}`
  );
}

export function analyzePromptQuality(sessionId: string) {
  return request<AnalysisApiResult>('/analysis/prompt-quality', {
    method: 'POST',
    body: JSON.stringify({ sessionId }),
  });
}

export function findRecurringInsights(body?: { projectId?: string; limit?: number }) {
  return request<{
    success: boolean;
    groups?: Array<{ insightIds: string[]; theme: string }>;
    updatedCount?: number;
    error?: string;
  }>('/analysis/recurring', {
    method: 'POST',
    body: JSON.stringify(body ?? {}),
  });
}

// ── Export ────────────────────────────────────────────────────────────────────

export async function exportMarkdown(body: {
  sessionIds?: string[];
  projectId?: string;
}): Promise<string> {
  const res = await fetch(`${BASE}/export/markdown`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText);
    throw new Error(`Export failed ${res.status}: ${text}`);
  }
  return res.text();
}

import { useMemo, useState } from 'react';
import { Link } from 'react-router';
import { useDashboardStats } from '@/hooks/useAnalytics';
import { useSessions } from '@/hooks/useSessions';
import { useInsights } from '@/hooks/useInsights';
import { useProjects } from '@/hooks/useProjects';
import { StatsHero } from '@/components/dashboard/StatsHero';
import { DashboardActivityChart } from '@/components/dashboard/DashboardActivityChart';
import { ActivityFeed } from '@/components/dashboard/ActivityFeed';
import { BulkAnalyzeButton } from '@/components/analysis/BulkAnalyzeButton';
import { StatsHeroSkeleton } from '@/components/skeletons/StatsHeroSkeleton';
import { ErrorCard } from '@/components/ErrorCard';
import { Card, CardContent, CardHeader } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import type { DailyStats } from '@/lib/types';
import { Sparkles, ArrowRight } from 'lucide-react';

type DashboardRange = '7d' | '30d' | '90d' | 'all';

function getGreeting(): string {
  const hour = new Date().getHours();
  if (hour < 12) return 'Good morning';
  if (hour < 17) return 'Good afternoon';
  return 'Good evening';
}

export default function DashboardPage() {
  const [range, setRange] = useState<DashboardRange>('7d');

  const { data: dashStats, isLoading: statsLoading, isError: statsError, refetch: refetchStats } = useDashboardStats(range);
  const { data: sessions = [], isLoading: sessionsLoading, isError: sessionsError, refetch: refetchSessions } = useSessions({ limit: 500 });
  const { data: insights = [], isLoading: insightsLoading } = useInsights();
  const { data: projects = [] } = useProjects();

  const loading = statsLoading || sessionsLoading || insightsLoading;
  const hasError = statsError || sessionsError;

  const todayLabel = new Date().toLocaleDateString(undefined, {
    month: 'long',
    day: 'numeric',
  });

  // Sessions not yet analyzed
  const analyzedSessionIds = new Set(insights.map((i) => i.session_id));
  const unanalyzedSessions = sessions.filter((s) => !analyzedSessionIds.has(s.id));

  // Build daily stats for activity chart
  const dailyStats: DailyStats[] = useMemo(() => {
    const now = Date.now();
    const rangeDays = range === '7d' ? 7 : range === '30d' ? 30 : range === '90d' ? 90 : Infinity;
    const cutoff = rangeDays === Infinity ? 0 : now - rangeDays * 86_400_000;

    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
    for (const s of sessions) {
      if (new Date(s.started_at).getTime() < cutoff) continue;
      const date = s.started_at.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].session_count++;
    }
    for (const i of insights) {
      if (new Date(i.timestamp).getTime() < cutoff) continue;
      const date = i.timestamp.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].insight_count++;
    }
    return Object.entries(grouped)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([date, counts]) => ({
        date,
        session_count: counts.session_count,
        message_count: 0,
        insight_count: counts.insight_count,
      }));
  }, [sessions, insights, range]);

  // Compute stats for hero — all from dashStats (range-filtered)
  const totalTokens = dashStats
    ? (dashStats.total_input_tokens ?? 0) +
      (dashStats.total_output_tokens ?? 0) +
      (dashStats.cache_creation_tokens ?? 0) +
      (dashStats.cache_read_tokens ?? 0)
    : 0;

  const totalCost = dashStats?.estimated_cost_usd ?? 0;

  const tokenBreakdown = dashStats
    ? {
        inputTokens: dashStats.total_input_tokens ?? 0,
        outputTokens: dashStats.total_output_tokens ?? 0,
        cacheCreationTokens: dashStats.cache_creation_tokens ?? 0,
        cacheReadTokens: dashStats.cache_read_tokens ?? 0,
      }
    : undefined;

  return (
    <div className="p-3 lg:p-4 space-y-2">
      {/* Greeting header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-lg font-bold">{getGreeting()}.</h1>
          {!loading && (
            <p className="text-muted-foreground text-xs animate-in fade-in slide-in-from-bottom-2 duration-300">
              {sessions.length} session{sessions.length !== 1 ? 's' : ''} loaded
              {' '}&middot; {projects.length} project{projects.length !== 1 ? 's' : ''}
            </p>
          )}
        </div>
        <span className="text-sm text-muted-foreground">{todayLabel}</span>
      </div>

      {/* Error state */}
      {hasError && !loading && (
        <ErrorCard
          message="Failed to load dashboard data"
          onRetry={() => { refetchStats(); refetchSessions(); }}
        />
      )}

      {/* All-time stats hero */}
      {loading ? (
        <StatsHeroSkeleton />
      ) : (
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
          <StatsHero
            totalSessions={dashStats?.session_count ?? sessions.length}
            totalMessages={dashStats?.total_messages ?? 0}
            totalToolCalls={dashStats?.total_tool_calls ?? 0}
            totalDurationMin={dashStats?.total_duration_min ?? 0}
            totalProjects={dashStats?.active_projects ?? projects.length}
            isExact={true}
            totalTokens={totalTokens > 0 ? totalTokens : undefined}
            totalCost={totalCost > 0 ? totalCost : undefined}
            tokenBreakdown={tokenBreakdown}
          />
        </div>
      )}

      {/* Activity chart */}
      {loading ? (
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-1">
            <Skeleton className="h-4 w-16" />
            <div className="flex gap-1">
              <Skeleton className="h-7 w-10 rounded" />
              <Skeleton className="h-7 w-10 rounded" />
              <Skeleton className="h-7 w-8 rounded" />
            </div>
          </CardHeader>
          <CardContent>
            <Skeleton className="h-[200px] w-full rounded" />
          </CardContent>
        </Card>
      ) : (
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-150">
          <DashboardActivityChart data={dailyStats} range={range} onRangeChange={setRange} />
        </div>
      )}

      {/* Needs Attention banner */}
      {unanalyzedSessions.length > 0 && (
        <Card className="border-amber-500/20 bg-amber-500/5 hover:shadow-md transition-shadow animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
          <CardContent className="flex items-center justify-between py-2.5">
            <div className="flex items-center gap-2">
              <Sparkles className="h-4 w-4 text-amber-600" />
              <div>
                <p className="text-sm font-medium">
                  {unanalyzedSessions.length} session{unanalyzedSessions.length !== 1 ? 's' : ''}{' '}
                  without analysis
                </p>
                <p className="text-xs text-muted-foreground">
                  Generate AI insights to extract learnings and decisions
                </p>
              </div>
            </div>
            <BulkAnalyzeButton sessions={unanalyzedSessions} />
          </CardContent>
        </Card>
      )}

      {/* Unified activity feed */}
      <div
        className={
          loading ? '' : 'animate-in fade-in slide-in-from-bottom-2 duration-300 delay-300'
        }
      >
        <div className="flex items-center justify-between mb-1">
          <h2 className="text-xs font-semibold">Recent Activity</h2>
          <Link
            to="/sessions"
            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            View all
            <ArrowRight className="h-3 w-3" />
          </Link>
        </div>
        <Card>
          <CardContent className="px-4 py-2">
            {loading ? (
              <div className="divide-y divide-border">
                {[...Array(4)].map((_, i) => (
                  <div key={i} className="py-2">
                    <div className="flex items-center justify-between gap-2">
                      <div className="flex items-center gap-2 min-w-0">
                        <Skeleton className="h-6 w-6 rounded-md shrink-0" />
                        <Skeleton className="h-4 w-48" />
                        <Skeleton className="h-3.5 w-20" />
                      </div>
                      <Skeleton className="h-3.5 w-16 shrink-0" />
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <ActivityFeed sessions={sessions} insights={insights} limit={7} />
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
